import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import { execSync } from 'node:child_process';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const publicDir = path.join(__dirname, '../frontend/public');

/** Minimal valid 1x1 JPEG (decodable by browsers and image libraries). */
const minimalJpeg = Buffer.from(
  '',
  'base64'
);

const isValidPlaceholder = (filePath) => {
  if (!fs.existsSync(filePath)) return false;
  const onDisk = fs.readFileSync(filePath);
  return onDisk.length === minimalJpeg.length && onDisk.equals(minimalJpeg);
};

const raw = execSync('pnpm exec tsx scripts/list-catalog-image-paths.ts', {
  cwd: path.join(__dirname, '..'),
  encoding: 'utf8'
});
const imagePaths = JSON.parse(raw);

let written = 0;

for (const webPath of imagePaths) {
  const relative = webPath.replace(/^\//, '');
  const filePath = path.join(publicDir, relative);
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  if (!isValidPlaceholder(filePath)) {
    fs.writeFileSync(filePath, minimalJpeg);
    written += 1;
  }
}

console.log(`Catalog images ready (${imagePaths.length} paths, ${written} written).`);
